import boto3
from botocore.exceptions import ClientError
import os
import time
import urllib.request

# Set up S3 client
s3 = boto3.client('s3')

# Set up EC2 instance
ec2 = boto3.resource('ec2')

# Set up PhantomJS or headless Chrome
phantomjs_path = '/usr/local/bin/phantomjs'
chrome_path = '/usr/local/bin/google-chrome'

def generate_screenshot(url):
    # Check if URL is valid
    try:
        urllib.request.urlopen(url)
    except urllib.error.URLError as e:
        print("Invalid URL")
        return None
    
    # Set up PhantomJS or headless Chrome
    if os.path.exists(phantomjs_path):
        browser = phantomjs_path
    elif os.path.exists(chrome_path):
        browser = chrome_path
    else:
        print("No supported browser found")
        return None
    
    # Take screenshot and store in S3
    try:
        s3.put_object(Body=browser.screenshot(url), Bucket='your-bucket-name', Key=f'{url}.png')
    except ClientError as e:
        print("S3 error")
        return None
    
    # Return screenshot URL
    return f'https://s3.amazonaws.com/your-bucket-name/{url}.png'